oxy_webhelp_navlinks = {"tocId-d27248e19205":{"topics":[{"title":"Rubrik backup components for Azure SQL MI","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects Azure SQL Managed Instances by taking Rubrik backups         that use several key components: Rubrik Exocompute for data processing, Change Data Capture         to ensure transactional consistency in BACPAC files, the Cloud Storage Layer for efficient         storage, and snapshot immutability for cyber resilience. Rubrik backups offer significant         advantages, including a logical air gap and flexible recovery options.<\/p>","href":"saas\/azr_sql_mi_rbk_backup_components.html","attributes":{"data-id":"azr_sql_mi_rbk_backup_components"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_rbk_backup_components-d27248e19206","topics":[]},{"title":"Supported datatypes for Azure SQL MI Rubrik backups","shortdesc":"<p class=\"shortdesc\">Information about the datatypes that <span class=\"ph\">RSC<\/span> supports for the Azure SQL         Managed Instance Rubrik backups.<\/p>","href":"saas\/azr_sql_mi_supp_datatypes_rbk_backups.html","attributes":{"data-id":"azr_sql_mi_supp_datatypes_rbk_backups"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_supp_datatypes_rbk_backups-d27248e19219","topics":[]}]}};